code_examples.insecureCode:
// ❌ Insecure: Trusts the UI to hide the route
app.post('/api/settings/update', (req, res) => {
  // Error: We forgot to check if req.user is an admin!
  const config = req.body;
  DB.settings.update(config);
  res.status(200).send('System reconfigured.');
});

code_examples.secureCode:
// ✓ Secure: Enforces role-based access at the route level
const isAdmin = (req, res, next) => {
  if (req.user && req.user.role === 'ADMIN') return next();
  return res.status(403).json({ error: 'Access Denied: Admin privileges required.' });
};

app.post('/api/settings/update', isAdmin, (req, res) => {
  DB.settings.update(req.body);
  res.json({ status: 'Success' });
});
